Here's a simple C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:

```cpp
#include <iostream>
#include <fstream>
#include <string>

int main() {
    std::string filename, word, line;
    std::ifstream file;
    int count = 0;

    // Get the filename from user input
    std::cout << "Enter the filename: ";
    std::cin >> filename;

    // Get the word to search for from user input
    std::cout << "Enter the word to search for: ";
    std::cin >> word;

    // Open the file
    file.open(filename.c_str());

    // Check if the file is opened successfully
    if (!file.is_open()) {
        std::cerr << "Error opening file: " << filename << std::endl;
        return 1;
    }

    // Read the file line by line
    while (std::getline(file, line)) {
        size_t pos = line.find(word);
        // If the word is found in the current line, increment the counter
        if (pos != std::string::npos) {
            count++;
        }
    }

    // Close the file
    file.close();

    // Print the number of occurrences of the word in the file
    std::cout << "The word \"" << word << "\" occurs " << count << " times in the file." << std::endl;

    return 0;
}
```

To compile and run the program, save it to a file named `word_count.cpp` and use a C++ compiler like g++:

```sh
g++ word_count.cpp -o word_count
./word_count
```

The program will prompt you for a filename and a word to search for. After that, it will display the number of occurrences of the word in the file.

Here's an implementation of the binary search algorithm in Python:

```python
def binary_search(arr, low, high, x):
  # Check base case
  if high >= low:

    mid = (high + low) // 2
    guess = arr[mid]

    # If element is present at the middle itself
    if guess == x:
        return mid

    # If element is smaller than mid, then it can only be present in left subarray
    if guess < x:
        return binary_search(arr, low, mid - 1, x)

    # Else the element can only be present in right subarray
    else:
        return binary_search(arr, mid + 1, high, x)

  else:
    # Element is not present in array
    return -1

# Test array
arr = [2, 3, 4, 10, 40]
x = 10

# Function call
result = binary_search(arr, 0, len(arr)-1, x)

if result != -1:
  print("Element is present at index", str(result))
else:
  print("Element is not present in array")
```

In this example, the `binary_search` function takes an array `arr`, the lower and upper bounds of the search range `low` and `high`, and the target element `x` as arguments. The function recursively calculates the middle index `mid` of the current search range and compares the element at that index with the target element. Depending on the comparison result, the search continues in the left or right subarray. The search terminates when the target element is found or when the search range is empty.
